const calcMin=({containerWidth:t=0,layerWidth:e=0,slides:i=[],viewportOffsetWidth:r=0,align:c,isCenterWithCustomWidth:n})=>{switch(c){case"left":return t-e;case"right":return r-e;case"center":var h,s;return n&&i.length?({coordX:h,width:s}=i[i.length-1],r/2-h-s/2):r-(t-r)/2-e}},calcMax=({slides:t=[],viewportOffsetWidth:e=0,isCenterWithCustomWidth:i})=>{return i&&t.length?({width:i,coordX:t}=t[0],e/2-t-i/2):0};export{calcMin,calcMax};